import java.util.*;
import java.util.function.Consumer;

public class EventBus {

    private final Map<String, List<Consumer<Object>>> subscribers = new LinkedHashMap<>();

    public void subscribe(String eventType, Consumer<Object> handler) {
        subscribers.computeIfAbsent(eventType, k -> new ArrayList<>()).add(handler);
    }

    public void unsubscribe(String eventType, Consumer<Object> handler) {
        List<Consumer<Object>> handlers = subscribers.get(eventType);
        if (handlers != null) handlers.remove(handler);
    }

    public int publish(String eventType, Object payload) {
        // Notify all subscribers for eventType, return count of notified subscribers
        return 0; // TODO
    }

    public int subscriberCount(String eventType) {
        return subscribers.getOrDefault(eventType, List.of()).size();
    }

    public static void main(String[] args) {
        EventBus bus = new EventBus();
        List<String> received = new ArrayList<>();

        Consumer<Object> handler1 = e -> received.add("H1: " + e);
        Consumer<Object> handler2 = e -> received.add("H2: " + e);

        bus.subscribe("order.created", handler1);
        bus.subscribe("order.created", handler2);
        bus.subscribe("order.cancelled", handler1);

        int notified = bus.publish("order.created", "Order#42");
        System.out.println("Notified: " + notified);
        System.out.println(received);

        bus.unsubscribe("order.created", handler1);
        System.out.println("After unsub count: " + bus.subscriberCount("order.created"));
    }
}

import java.util.*;

public class SortContext {

    interface SortStrategy {
        List<Integer> sort(List<Integer> input);
        String strategyName();
    }

    static class BubbleSortStrategy implements SortStrategy {
        public List<Integer> sort(List<Integer> input) {
            List<Integer> list = new ArrayList<>(input);
            int n = list.size();
            for (int i = 0; i < n - 1; i++)
                for (int j = 0; j < n - i - 1; j++)
                    if (list.get(j) > list.get(j + 1)) {
                        int tmp = list.get(j);
                        list.set(j, list.get(j + 1));
                        list.set(j + 1, tmp);
                    }
            return list;
        }
        public String strategyName() { return "BubbleSort"; }
    }

