        TextEditor editor = new TextEditor();
        editor.executeCommand(editor.new InsertCommand(0, "Hello"));
        editor.executeCommand(editor.new InsertCommand(5, " World"));
        System.out.println(editor.getContent());
        editor.undo();
        System.out.println(editor.getContent());
        editor.redo();
        System.out.println(editor.getContent());
        editor.executeCommand(editor.new DeleteCommand(5, 11));
        System.out.println(editor.getContent());
        editor.undo();
        System.out.println(editor.getContent());
    }
